import{_ as a,c as t,o as i,aj as s}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Virtual Private Networks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security/vpn.md","filePath":"guide/security/vpn.md","lastUpdated":1777621302000}'),r={name:"guide/security/vpn.md"};function n(o,e,l,p,d,h){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="virtual-private-networks" tabindex="-1">Virtual Private Networks <a class="header-anchor" href="#virtual-private-networks" aria-label="Permalink to &quot;Virtual Private Networks&quot;">​</a></h1><p>A <abbr title="Virtual Private Network">VPN</abbr> is a network control that limits who can reach Iroha services. It is most useful for private and consortium deployments where validators, application backends, and operators should communicate over private addresses instead of open internet routes.</p><p>A VPN does not replace Iroha peer keys, account keys, permissions, firewall rules, monitoring, or secure key storage. Treat it as one layer in the deployment boundary: the VPN narrows network reachability, while Iroha configuration and governance decide which peers and accounts are trusted.</p><h2 id="when-to-use-a-vpn" tabindex="-1">When to Use a VPN <a class="header-anchor" href="#when-to-use-a-vpn" aria-label="Permalink to &quot;When to Use a VPN&quot;">​</a></h2><p>Use a VPN when:</p><ul><li>validators are operated by different organizations or in different hosting environments</li><li>Torii should only be reachable by application backends, operators, or trusted clients</li><li>metrics, logs, SSH, or other administration endpoints must stay on a private operator network</li><li>a test or staging network should resemble production access controls without exposing public endpoints</li></ul><p>A VPN is not required for every deployment. Public networks may intentionally expose Torii through a public gateway, load balancer, or reverse proxy. Even in that case, keep validator peer-to-peer traffic and administration endpoints on a restricted network whenever possible.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>A browser VPN only protects traffic from that browser. It does not protect <code>irohad</code>, CLI, SDK, SSH, metrics, or backup traffic unless those processes are routed through the same private network.</p></div><h2 id="deployment-pattern" tabindex="-1">Deployment Pattern <a class="header-anchor" href="#deployment-pattern" aria-label="Permalink to &quot;Deployment Pattern&quot;">​</a></h2><p>For a private validator mesh, give every validator a stable VPN address or private DNS name. Configure peers so their advertised peer-to-peer addresses are reachable from the other validators over that network:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">trusted_peers = [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;PUBLIC_KEY_1@10.20.0.11:1337&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;PUBLIC_KEY_2@10.20.0.12:1337&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;PUBLIC_KEY_3@10.20.0.13:1337&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;PUBLIC_KEY_4@10.20.0.14:1337&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">network</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10.20.0.11:1337&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">public_address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10.20.0.11:1337&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">torii</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10.20.0.11:8080&quot;</span></span></code></pre></div><p>Use the address assigned to the current peer in <code>network.address</code> and <code>network.public_address</code>. Each peer should list the same trusted peer identities, but with addresses that are reachable from its own VPN route table.</p><p>Client and CLI configurations should point at a Torii endpoint reachable through the VPN or through a controlled internal gateway:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">torii_url = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://10.20.0.11:8080&quot;</span></span></code></pre></div><p>If Torii must be available outside the VPN, put it behind a reverse proxy or load balancer that provides TLS, authentication, rate limiting, and logging. Avoid exposing raw peer-to-peer ports or administration endpoints directly to the public internet.</p><h2 id="firewall-rules" tabindex="-1">Firewall Rules <a class="header-anchor" href="#firewall-rules" aria-label="Permalink to &quot;Firewall Rules&quot;">​</a></h2><p>Use host and cloud firewall rules even when a VPN is present:</p><table tabindex="0"><thead><tr><th>Service</th><th>Recommended access</th></tr></thead><tbody><tr><td>Peer-to-peer port</td><td>Other validator VPN addresses only</td></tr><tr><td>Torii</td><td>Application backends, operators, or trusted client VPN ranges</td></tr><tr><td>Metrics and health checks</td><td>Monitoring systems on the operator network</td></tr><tr><td>SSH and administration</td><td>Bastion host, privileged operator VPN range, or break-glass process</td></tr><tr><td>Backups and storage replication</td><td>Backup systems on a private network</td></tr></tbody></table><p>Default-deny rules are easier to audit than broad allow rules. When a new peer joins the network, update the VPN membership, firewall allow list, and Iroha trusted peer configuration as one coordinated change.</p><h2 id="operational-checklist" tabindex="-1">Operational Checklist <a class="header-anchor" href="#operational-checklist" aria-label="Permalink to &quot;Operational Checklist&quot;">​</a></h2><ul><li>Choose an audited and actively maintained VPN implementation, such as WireGuard, IPsec, or an organization-approved managed private network.</li><li>Use unique VPN credentials for each host and operator. Do not share VPN keys between validators.</li><li>Keep VPN credentials separate from Iroha private keys and genesis signing material.</li><li>Monitor VPN latency, packet loss, reconnects, and route changes. Consensus is sensitive to sustained network instability.</li><li>Test the effective MTU. Packet fragmentation can look like intermittent peer or Torii failures.</li><li>Document which VPN ranges are allowed to reach peer-to-peer, Torii, metrics, SSH, and backup endpoints.</li><li>Rotate VPN credentials when a host, operator account, or organization leaves the network.</li><li>Avoid a single VPN gateway as the only route between validators. Plan redundant gateways or site-to-site routes for production networks.</li><li>Include VPN failures in incident response drills so operators know when to distinguish a network partition from an Iroha process failure.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/iroha-2-docs/guide/security/security-principles.html">Security Principles</a></li><li><a href="/iroha-2-docs/guide/security/operational-security.html">Operational Security</a></li><li><a href="/iroha-2-docs/guide/configure/keys-for-network-deployment.html">Keys for Network Deployment</a></li><li><a href="/iroha-2-docs/guide/configure/peer-management.html">Peer Management</a></li><li><a href="/iroha-2-docs/reference/peer-config/">Peer Configuration Reference</a></li></ul>`,23)])])}const k=a(r,[["render",n]]);export{u as __pageData,k as default};
